-- =============================================================================
-- Hotel Recommendation System — RAG Pipeline
-- Milestone 1: Schema Design and DDL
-- Authors : Emmanuel Mukange (ZDA24B029), Raudhat Ramadhan (ZDA24B010)
-- Course  : Database Management Systems — IIT Madras Zanzibar
-- DBMS    : PostgreSQL 15+
-- Run     : psql -U <user> -d <database> -f schema.sql
-- =============================================================================

-- VECTOR STORE NOTE:
-- For this project, Pinecone will be used as the vector store for embeddings
-- generated by sentence-transformers, while PostgreSQL handles all relational
-- data. This is explicitly permitted by the Track A specification:
-- CREATE EXTENSION IF NOT EXISTS vector;

-- Drop tables in reverse FK dependency order for clean re-runs
DROP TABLE IF EXISTS reviews   CASCADE;
DROP TABLE IF EXISTS bookings  CASCADE;
DROP TABLE IF EXISTS users     CASCADE;
DROP TABLE IF EXISTS hotels    CASCADE;
DROP TABLE IF EXISTS room_types CASCADE;

-- =============================================================================
-- TABLE: room_types
-- Purpose : Lookup table for room categories.  Extracted into its own table
--           to avoid repeating room metadata in every booking row (3NF).
-- FDs     : room_type_id → {type_name, max_occupancy, price_multiplier}
-- =============================================================================
CREATE TABLE room_types (
    room_type_id      SERIAL        PRIMARY KEY,
    -- Human-readable label; must be unique across all room categories
    type_name         VARCHAR(50)   NOT NULL UNIQUE,
    -- Maximum number of guests allowed in this room type
    max_occupancy     SMALLINT      NOT NULL CHECK (max_occupancy BETWEEN 1 AND 10),
    -- Multiplier applied to a hotel's base price_per_night
    price_multiplier  NUMERIC(4,2)  NOT NULL CHECK (price_multiplier > 0)
);

-- =============================================================================
-- TABLE: hotels
-- Purpose : Core entity. Real hotel records sourced from Kaggle dataset,
--           enriched with synthetic columns (rating, price, amenities).
-- FDs     : hotel_id → all non-key columns  (trivially 3NF — no transitive deps)
-- Note    : 'amenities' is a denormalised text field kept intentionally flat
--           because amenities will be embedded as free text for vector search.
--           A full amenity junction table would add no RAG benefit here.
-- =============================================================================
CREATE TABLE hotels (
    hotel_id          SERIAL          PRIMARY KEY,
    name              VARCHAR(200)    NOT NULL,
    city              VARCHAR(100)    NOT NULL,
    state             CHAR(2)         NOT NULL,
    zip_code          VARCHAR(10),
    address           VARCHAR(255),
    phone             VARCHAR(20),
    website           VARCHAR(500),
    -- Budget | Mid-range | Boutique | Luxury | Resort
    category          VARCHAR(50)     NOT NULL,
    -- 1.0–5.0 aggregate star rating
    star_rating       NUMERIC(2,1)    NOT NULL CHECK (star_rating BETWEEN 1.0 AND 5.0),
    -- Nightly base rate in USD before room-type multiplier
    price_per_night   NUMERIC(8,2)    NOT NULL CHECK (price_per_night > 0),
    -- Comma-separated amenity list — source text for sentence-transformer embeddings
    amenities         TEXT,
    total_rooms       SMALLINT        CHECK (total_rooms > 0),
    created_at        TIMESTAMPTZ     NOT NULL DEFAULT now()
);

-- =============================================================================
-- TABLE: users
-- Purpose : Application users / travellers.
-- FDs     : user_id → all columns; email is also a candidate key (UNIQUE).
--           No transitive dependencies — 3NF satisfied.
-- =============================================================================
CREATE TABLE users (
    user_id           SERIAL          PRIMARY KEY,
    first_name        VARCHAR(100)    NOT NULL,
    last_name         VARCHAR(100)    NOT NULL,
    -- Natural candidate key; used for login / de-duplication
    email             VARCHAR(255)    NOT NULL UNIQUE,
    phone             VARCHAR(20),
    nationality       VARCHAR(100),
    date_of_birth     DATE,
    -- Row creation timestamp (UTC)
    created_at        DATE            NOT NULL DEFAULT CURRENT_DATE
);

-- =============================================================================
-- TABLE: bookings
-- Purpose : Records each hotel reservation — the central fact table.
-- FDs     : booking_id → all columns.
--           total_price is functionally determined by (hotel_id, room_type_id,
--           check_in_date, check_out_date) but is stored for historical accuracy
--           (prices change; we must record the price at booking time).
-- Keys    : FK → users, hotels, room_types
-- =============================================================================
CREATE TABLE bookings (
    booking_id        SERIAL          PRIMARY KEY,
    user_id           INT             NOT NULL REFERENCES users(user_id)    ON DELETE CASCADE,
    hotel_id          INT             NOT NULL REFERENCES hotels(hotel_id)  ON DELETE RESTRICT,
    room_type_id      INT             NOT NULL REFERENCES room_types(room_type_id),
    check_in_date     DATE            NOT NULL,
    check_out_date    DATE            NOT NULL,
    -- Derived check: checkout must follow check-in
    CONSTRAINT chk_dates CHECK (check_out_date > check_in_date),
    num_guests        SMALLINT        NOT NULL DEFAULT 1 CHECK (num_guests >= 1),
    -- Price locked at booking time in USD
    total_price       NUMERIC(10,2)   NOT NULL CHECK (total_price >= 0),
    -- confirmed | cancelled | completed | no_show
    status            VARCHAR(20)     NOT NULL DEFAULT 'confirmed'
                          CHECK (status IN ('confirmed','cancelled','completed','no_show')),
    created_at        DATE            NOT NULL DEFAULT CURRENT_DATE
);

-- =============================================================================
-- TABLE: reviews
-- Purpose : Textual reviews per hotel by a user.
--           review_text is the primary corpus for sentence-transformer
--           embeddings stored in pgvector (RAG retrieval layer).
-- FDs     : review_id → all columns.
--           (hotel_id, user_id) is a candidate key — one review per user/hotel.
-- Keys    : FK → hotels, users
-- =============================================================================
CREATE TABLE reviews (
    review_id         SERIAL          PRIMARY KEY,
    hotel_id          INT             NOT NULL REFERENCES hotels(hotel_id)  ON DELETE CASCADE,
    user_id           INT             NOT NULL REFERENCES users(user_id)    ON DELETE SET NULL,
    -- 1.0–5.0 user-submitted rating
    rating            NUMERIC(2,1)    NOT NULL CHECK (rating BETWEEN 1.0 AND 5.0),
    -- Free-text review body; this column feeds the RAG embedding pipeline
    review_text       TEXT            NOT NULL,
    review_date       DATE            NOT NULL DEFAULT CURRENT_DATE,
    -- Community upvotes on the review
    helpful_votes     INT             NOT NULL DEFAULT 0 CHECK (helpful_votes >= 0),
    -- One review per (user, hotel) pair
    CONSTRAINT uq_user_hotel_review UNIQUE (hotel_id, user_id)
);

-- =============================================================================
-- INDEXES
-- All are B-Tree (PostgreSQL default) unless stated otherwise.
-- EXPLAIN ANALYZE evidence will be collected separately in the RAG notebook.
-- =============================================================================

-- Frequent filter: find bookings by user
CREATE INDEX idx_bookings_user_id    ON bookings(user_id);

-- Frequent filter: find all bookings for a hotel (availability check)
CREATE INDEX idx_bookings_hotel_id   ON bookings(hotel_id);

-- Range queries: show bookings in a date window
CREATE INDEX idx_bookings_checkin    ON bookings(check_in_date);

-- City-based hotel search (most common user query)
CREATE INDEX idx_hotels_city         ON hotels(city);

-- Rating-based filtering (e.g. WHERE star_rating >= 4)
CREATE INDEX idx_hotels_rating       ON hotels(star_rating);

-- Price-range filtering
CREATE INDEX idx_hotels_price        ON hotels(price_per_night);

-- Lookup reviews by hotel (JOIN-heavy in RAG retrieval)
CREATE INDEX idx_reviews_hotel_id    ON reviews(hotel_id);

