INSERT INTO reviews (review_id, hotel_id, user_id, rating, review_text, review_date, helpful_votes) VALUES
    (1, 1, 133, 4.4, 'My visit to Courtyard by Marriott was an interesting experience worth documenting. Breakfast was exceptional — fresh and varied. Location was perfect for exploring the city. Wi-Fi connection was a bit inconsistent. Notable highlights include: Airport Shuttle and Business Centre. For budget travellers, Courtyard by Marriott is a solid choice.', '2025-09-05', 109),
    (2, 2, 44, 4.0, 'My visit to Holiday Inn was an interesting experience worth documenting. Breakfast was exceptional — fresh and varied. The pool area was stunning and never overcrowded. Wi-Fi connection was a bit inconsistent. Notable highlights include: Gym and Free Wi-Fi. For budget travellers, Holiday Inn is a solid choice.', '2024-10-25', 9),
    (3, 3, 6, 4.0, 'I booked Holiday Inn Express for a business trip and here are my thoughts. The staff were incredibly welcoming and attentive. The pool area was stunning and never overcrowded. The room was adequate for the price. Notable highlights include: Free Wi-Fi and Room Service. For budget travellers, Holiday Inn Express is a solid choice.', '2025-11-30', 65),
    (4, 4, 17, 3.3, 'My visit to IHG Hotels & Resorts was an interesting experience worth documenting. The staff were incredibly welcoming and attentive. Some areas of the hotel felt slightly dated. The noise from the street was disruptive. The price felt a bit high given the facilities. Notable highlights include: Rooftop Terrace and Gym. The boutique character of IHG Hotels & Resorts really set it apart.', '2025-04-12', 26),
    (5, 5, 62, 2.2, 'My visit to avid hotels was an interesting experience worth documenting. The staff were incredibly welcoming and attentive. Parking was limited but manageable. The gym equipment needs upgrading. The price felt a bit high given the facilities. Notable highlights include: Spa and Laundry Service. The boutique character of avid hotels really set it apart.', '2025-07-16', 109),
    (6, 6, 150, 4.1, 'Just returned from a wonderful stay at Best Western Plus Miami Executive Airport Hotel & Suites. The spa facilities were world-class. Room was spotlessly clean and beautifully furnished. The room was adequate for the price. Notable highlights include: Spa and Gym. The resort atmosphere at Best Western Plus Miami Executive Airport Hotel & Suites was genuinely relaxing.', '2024-07-07', 91),
    (7, 7, 59, 4.9, 'Just returned from a wonderful stay at Erg Hotel Inc. The spa facilities were world-class. The staff were incredibly welcoming and attentive. Room was spotlessly clean and beautifully furnished. Room service took longer than expected. Notable highlights include: 24-Hour Front Desk and Restaurant. Overall, Erg Hotel Inc delivers good mid-range value.', '2024-04-30', 23),
    (8, 8, 132, 3.8, 'I recently stayed at Koala Tours And Transportation and wanted to share my experience. Breakfast was exceptional — fresh and varied. Check-in was seamless and very professional. The air conditioning was a little loud at night. Wi-Fi connection was a bit inconsistent. The price felt a bit high given the facilities. Notable highlights include: Business Centre and Kids Club. For budget travellers, Koala Tours And Transportation is a solid choice.', '2025-01-05', 14),
    (9, 9, 99, 2.0, 'I recently stayed at Le Pavilion At Hotel Inter-Continental and wanted to share my experience. The spa facilities were world-class. Room service took longer than expected. The gym equipment needs upgrading. The price felt a bit high given the facilities. Notable highlights include: Restaurant and Swimming Pool. The resort atmosphere at Le Pavilion At Hotel Inter-Continental was genuinely relaxing.', '2025-06-16', 10),
    (10, 10, 102, 3.0, 'I booked Biltmore Bar for a business trip and here are my thoughts. Location was perfect for exploring the city. Some areas of the hotel felt slightly dated. Check-out process was straightforward. Some staff seemed undertrained. Housekeeping missed our room one day. Notable highlights include: Conference Rooms and Kids Club. Overall, Biltmore Bar delivers good mid-range value.', '2024-08-15', 37),
    (11, 11, 129, 2.1, 'I recently stayed at Hotel Victor and wanted to share my experience. Great value for money — exceeded all expectations. Check-out process was straightforward. Wi-Fi connection was a bit inconsistent. The room was adequate for the price. Some staff seemed undertrained. The noise from the street was disruptive. Notable highlights include: Spa and Business Centre. The resort atmosphere at Hotel Victor was genuinely relaxing.', '2026-01-04', 66),
    (12, 12, 25, 2.4, 'I booked Massaro Group Inc for a business trip and here are my thoughts. The bed was the most comfortable I have ever slept in. Wi-Fi connection was a bit inconsistent. Check-out process was straightforward. Room service took longer than expected. The noise from the street was disruptive. The gym equipment needs upgrading. Notable highlights include: Gym and Bar. For budget travellers, Massaro Group Inc is a solid choice.', '2025-06-11', 25),
    (13, 13, 123, 2.5, 'I booked Tres Palmas Inn for a business trip and here are my thoughts. Great value for money — exceeded all expectations. Some areas of the hotel felt slightly dated. The air conditioning was a little loud at night. Some staff seemed undertrained. The gym equipment needs upgrading. Notable highlights include: Room Service and Restaurant. The resort atmosphere at Tres Palmas Inn was genuinely relaxing.', '2024-12-19', 77),
    (14, 14, 123, 4.5, 'My visit to Metro Hotel Couva was an interesting experience worth documenting. Breakfast was exceptional — fresh and varied. Great value for money — exceeded all expectations. Wi-Fi connection was a bit inconsistent. Notable highlights include: Spa and Concierge. Metro Hotel Couva truly lives up to its luxury billing.', '2024-08-05', 63),
    (15, 15, 74, 3.8, 'Just returned from a wonderful stay at Hotel Indigo. The staff were incredibly welcoming and attentive. Room was spotlessly clean and beautifully furnished. The room was adequate for the price. The air conditioning was a little loud at night. Room service took longer than expected. Some staff seemed undertrained. Notable highlights include: 24-Hour Front Desk and Pet-Friendly. The resort atmosphere at Hotel Indigo was genuinely relaxing.', '2026-01-21', 48),
    (16, 16, 102, 2.2, 'I recently stayed at Bookohotel and wanted to share my experience. Room was spotlessly clean and beautifully furnished. Room service took longer than expected. The air conditioning was a little loud at night. The restaurant menu could have more variety. Housekeeping missed our room one day. The gym equipment needs upgrading. Notable highlights include: Laundry Service and Pet-Friendly. For budget travellers, Bookohotel is a solid choice.', '2025-10-07', 64),
    (17, 17, 82, 3.0, 'I recently stayed at Touristguidepanama.Com and wanted to share my experience. The staff were incredibly welcoming and attentive. Wi-Fi connection was a bit inconsistent. The restaurant menu could have more variety. Some staff seemed undertrained. The gym equipment needs upgrading. Notable highlights include: Laundry Service and Parking. Touristguidepanama.Com truly lives up to its luxury billing.', '2025-08-24', 56),
    (18, 18, 138, 1.9, 'Just returned from a wonderful stay at Marriott''s. The spa facilities were world-class. Some areas of the hotel felt slightly dated. Check-out process was straightforward. Wi-Fi connection was a bit inconsistent. Some staff seemed undertrained. The price felt a bit high given the facilities. Notable highlights include: Room Service and Business Centre. Overall, Marriott''s delivers good mid-range value.', '2024-11-02', 91),
    (19, 19, 119, 3.1, 'I recently stayed at Khr and wanted to share my experience. Concierge went out of their way to help with restaurant reservations. Room service took longer than expected. Check-out process was straightforward. Some areas of the hotel felt slightly dated. The price felt a bit high given the facilities. Some staff seemed undertrained. Notable highlights include: Conference Rooms and Business Centre. Overall, Khr delivers good mid-range value.', '2025-01-15', 64),
    (20, 20, 16, 3.0, 'I booked CruiseOne for a business trip and here are my thoughts. Concierge went out of their way to help with restaurant reservations. Check-out process was straightforward. The air conditioning was a little loud at night. The gym equipment needs upgrading. The price felt a bit high given the facilities. Notable highlights include: Rooftop Terrace and Business Centre. Overall, CruiseOne delivers good mid-range value.', '2024-08-05', 75),
    (21, 21, 13, 2.3, 'My visit to Global Hotel Co was an interesting experience worth documenting. Check-in was seamless and very professional. The room was adequate for the price. The air conditioning was a little loud at night. Check-out process was straightforward. The gym equipment needs upgrading. Some staff seemed undertrained. Notable highlights include: EV Charging and Room Service. Overall, Global Hotel Co delivers good mid-range value.', '2025-05-31', 44),
    (22, 22, 111, 3.1, 'I recently stayed at Palmer House Hotel and wanted to share my experience. The pool area was stunning and never overcrowded. The restaurant menu could have more variety. The gym equipment needs upgrading. The noise from the street was disruptive. Notable highlights include: Restaurant and Swimming Pool. The boutique character of Palmer House Hotel really set it apart.', '2026-03-14', 111),
    (23, 23, 96, 2.0, 'Just returned from a wonderful stay at European Hotels. The staff were incredibly welcoming and attentive. Check-out process was straightforward. The room was adequate for the price. The restaurant menu could have more variety. Some staff seemed undertrained. The price felt a bit high given the facilities. Notable highlights include: Parking and Concierge. Overall, European Hotels delivers good mid-range value.', '2025-12-25', 89),
    (24, 24, 141, 3.8, 'My visit to Venezia Hotel was an interesting experience worth documenting. The bed was the most comfortable I have ever slept in. Concierge went out of their way to help with restaurant reservations. Wi-Fi connection was a bit inconsistent. The air conditioning was a little loud at night. Some staff seemed undertrained. Notable highlights include: Spa and Conference Rooms. For budget travellers, Venezia Hotel is a solid choice.', '2025-07-25', 86),
    (25, 25, 63, 2.8, 'My visit to South Florida Teen Travel was an interesting experience worth documenting. Breakfast was exceptional — fresh and varied. Some areas of the hotel felt slightly dated. Parking was limited but manageable. The restaurant menu could have more variety. Housekeeping missed our room one day. Some staff seemed undertrained. Notable highlights include: Free Wi-Fi and Restaurant. Overall, South Florida Teen Travel delivers good mid-range value.', '2025-08-16', 107),
